import "./style.scss"
import 'swiper/css';
import type { ResponseType } from "./type";
import { useEffect, useState } from "react";
import useRequest from "../../hooks/useRequest";
// import { message } from "../../utils/message";




const locallocation=localStorage.getItem("location");
const historyLocation=locallocation?JSON.parse(locallocation):null;

const defaultRequestData={
    url: '/home.json',
        method:'POST',
        data:{
            latitude:historyLocation?historyLocation.latitude:37.7304167,
            longitude:historyLocation?historyLocation.longitude:-122.384425
        }
}

function Home() {
    const [page,setPage]=useState(1);
    const [requestData,setRequestData]=useState(defaultRequestData)
    const {data} =useRequest<ResponseType>(requestData);
    //当定位发生改变的时候，访问后端接口重新获取所在位置 
    useEffect(()=>{
        if(navigator.geolocation&&!locallocation){
            navigator.geolocation.getCurrentPosition((position)=>{
                console.log("cccc",position)
                const {coords}=position;
                const {latitude,longitude}=coords;
            
                setRequestData({...defaultRequestData,data:{latitude,longitude}})
                
                localStorage.setItem("location",JSON.stringify(coords))
            },()=>{console.log()},{timeout:3000})
        }
    },[])
    return (
        <div className="page home-page">
           
            <div className="category">
            {data?.data.categories.map((item)=>{
                return  <div className="category-item" key={item.id}>
                <img className="category-item-img" src={item.imgUrl} alt={item.name}/>
                <p className="category-item-title">{item.name}</p>
             </div>
            })}
             
            </div>
            <div className="card">
                <h3 className="card-title">
                    <img className="card-title-img" src="http://statics.dell-lee.com/shopping/hot.png" alt="新品尝鲜"/>
                    新品尝鲜
                    <div className="card-title-more">更多<span className="iconfont">&#xe614;</span></div>
                </h3>
                <div className="card-content">
                    {data?.data.freshes.map((item)=>{
                        return <div className="card-content-item" key={item.id}> 
                        <img className="card-content-item-img"  alt={item.name} src={item.imgUrl}/>
                        <p className="card-content-item-desc">{item.name}</p>
                        <div className="card-content-item-price">
                            <span className="card-content-item-yen">&yen;</span>
                            {item.price}
                            <div className="iconfont">&#xe7e0;</div> 
                        </div>
                    </div>
                    })}
                    
                  
                </div>
                <div className="bottom">-我是有底线的-</div>
                <div className="docker">
                    <div className="docker-item docker-item-active">
                        <div className="iconfont ">&#xe7c6;</div>
                        <p className="docker-item-title">首页</p>
                    </div>
                    <div className="docker-item">
                        <div className="iconfont">&#xe63f;</div>
                        <p className="docker-item-title">分类</p>
                    </div>
                    <div className="docker-item">
                        <div className="iconfont">&#xe70b;</div>
                        <p className="docker-item-title">购物车</p>
                    </div>
                    <div className="docker-item">
                        <div className="iconfont">&#xe60d;</div>
                        <p className="docker-item-title">我的</p>
                    </div>
                </div>
            </div>
        </div>)
}


export default Home;
